/// <summary>
/// SysOperation controller class to update ETGSPAIN model fields in packing slips.
/// </summary>
class ETGSPAINSalesPackingSlipUpdateETGSPAINExtraFieldsController extends SysOperationServiceController
{
    ETGSPAINSalesPackingSlipUpdateETGSPAINExtraFieldsContract contract;

}

Method.Source:
/// <summary>
/// Override of the <c>canGoBatch</c> method to prevent batch execution.
/// </summary>
/// <returns>boolean</returns>
public boolean canGoBatch()
{
    return false;
}

/// <summary>
/// Override of the <c>new</c> method to process the operation synchronously.
/// </summary>
/// <param name = "_className">IdentifierName</param>
/// <param name = "_methodName">IdentifierName</param>
protected void new(IdentifierName _className = classStr(ETGSPAINSalesPackingSlipUpdateETGSPAINExtraFieldsService),
                   IdentifierName _methodName = methodStr(ETGSPAINSalesPackingSlipUpdateETGSPAINExtraFieldsService, process))
{
    super(_className, _methodName, SysOperationExecutionMode::Synchronous);
}

/// <summary>
/// Construct method for creating an instance of the class from <c>Args</c>.
/// </summary>
/// <param name = "_args">Args</param>
/// <returns>ETGSPAINSalesPackingSlipUpdateETGSPAINExtraFieldsController</returns>
public static ETGSPAINSalesPackingSlipUpdateETGSPAINExtraFieldsController construct(Args _args)
{
    ETGSPAINSalesPackingSlipUpdateETGSPAINExtraFieldsController controller = new ETGSPAINSalesPackingSlipUpdateETGSPAINExtraFieldsController();

    controller.parmArgs(_args);

    return  controller;
}

/// <summary>
/// Main method of the class.
/// </summary>
/// <param name = "_args">Args</param>
public static void main(Args _args)
{
    ETGSPAINSalesPackingSlipUpdateETGSPAINExtraFieldsController controller = ETGSPAINSalesPackingSlipUpdateETGSPAINExtraFieldsController::construct(_args);
    controller.initContract();
    controller.startOperation();        
}

/// <summary>
/// Method to initialize contract attributes.
/// </summary>
public void initContract()
{
    contract = this.getDataContractObject() as ETGSPAINSalesPackingSlipUpdateETGSPAINExtraFieldsContract;
    this.setContractAttributes();
    //this.getRecordCollection();
}

/// <summary>
/// Method to configure contract attributes.
/// </summary>
private void setContractAttributes()
{        
    contract.parmCallerBuffer(this.parmArgs().record());     
    contract.getInfoFromCallerBuffer();
}

